import { jsx } from 'react/jsx-runtime';
import { Button } from '../Button/Button.js';
import { classNames } from '../../helpers/classnames.js';

const ButtonSet = ({ buttons, size = 'small', direction = 'horizontal', className, dataTestId = 'ButtonSet', }) => {
    const rootClassName = classNames('dsb_button-set', `dsb_button-set__${direction}`, `dsb_button-set__${size}`, className);
    return (jsx("div", { className: rootClassName, "data-testid": dataTestId, children: buttons.map((button, index) => {
            const { id, ...buttonProps } = button;
            const key = id || `button-${index}`;
            return jsx(Button, { ...buttonProps, size: size, fullWidth: direction === 'vertical' }, key);
        }) }));
};

export { ButtonSet };
